('b19d2a3e-b87a-4c1d-8f2c-5f7e6a4b3d2c', 'admin@example.com', '$argon2id$v=19$m=65536,t=2,p=1$Q/3n/s+d/c/z/y/1/x/w/v/u/t/s/r/q/p/o$some_generated_hash_for_admin_pass', 'ADMIN')
